import{_ as e,o as d,c as t,ag as o}from"./chunks/framework-C5-Jzrz4.js";const c=JSON.parse('{"title":"应用层组件体系","description":"apps/web-antd/src/components 的业务组件、导出方式与使用场景","frontmatter":{"title":"应用层组件体系","description":"apps/web-antd/src/components 的业务组件、导出方式与使用场景"},"headers":[],"relativePath":"scripts/components/应用层组件体系.md","filePath":"scripts/components/应用层组件体系.md","lastUpdated":null}');const a=e({name:"scripts/components/应用层组件体系.md"},[["render",function(e,c,a,n,l,i){return d(),t("div",null,[...c[0]||(c[0]=[o('<h1 id="应用层组件体系" tabindex="-1">应用层组件体系 <a class="header-anchor" href="#应用层组件体系" aria-label="Permalink to &quot;应用层组件体系&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>apps/web-antd/src/components</code> 是应用层业务组件目录，组件围绕系统管理、工作流、上传、字典展示等场景封装。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>页面开发时选择业务组件</li><li>判断组件是否需要上升到 <code>packages</code> 抽象</li><li>对接表单适配器与上传/字典机制</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/components/*</code></li><li><code>apps/web-antd/src/components/global/index.ts</code></li><li><code>apps/web-antd/src/adapter/component/index.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="组件模块清单" tabindex="-1">组件模块清单 <a class="header-anchor" href="#组件模块清单" aria-label="Permalink to &quot;组件模块清单&quot;">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>目录</th><th>导出方式</th><th>主要职责</th></tr></thead><tbody><tr><td><code>DictTag</code></td><td><code>components/dict</code></td><td><code>index.ts</code> 导出 <code>DictTag</code> 与标签映射</td><td>按字典类型渲染标签/状态</td></tr><tr><td><code>MenuSelectTable</code>、<code>TreeSelectPanel</code></td><td><code>components/tree</code></td><td><code>index.ts</code> 导出</td><td>树形选择与菜单树面板</td></tr><tr><td><code>FileUpload</code>、<code>ImageUpload</code></td><td><code>components/upload</code></td><td><code>index.ts</code> 导出</td><td>文件与图片上传业务封装</td></tr><tr><td><code>Tinymce</code></td><td><code>components/tinymce</code></td><td><code>index.ts</code> 导出</td><td>富文本编辑器封装</td></tr><tr><td><code>CropperAvatar</code>、<code>CropperImage</code></td><td><code>components/cropper</code></td><td><code>index.ts</code> 导出</td><td>图片裁剪与头像裁剪</td></tr><tr><td><code>OptionsTag</code></td><td><code>components/table</code></td><td><code>index.ts</code> 导出</td><td>表格状态标签渲染</td></tr><tr><td><code>TenantToggle</code></td><td><code>components/tenant-toggle</code></td><td><code>index.ts</code> 导出</td><td>登录页租户切换</td></tr><tr><td><code>setupGlobalComponent</code>、<code>ApiSwitch</code></td><td><code>components/global</code></td><td><code>index.ts</code> 导出注册函数与 <code>ApiSwitch</code> 组件</td><td>全局组件注册与状态切换组件</td></tr></tbody></table><h3 id="全局组件注册" tabindex="-1">全局组件注册 <a class="header-anchor" href="#全局组件注册" aria-label="Permalink to &quot;全局组件注册&quot;">​</a></h3><p><code>components/global/index.ts</code> 当前注册：</p><ul><li><code>AButton</code>（<code>antdv-next</code> Button）</li><li><code>ActionButton</code>（表格操作按钮封装）</li></ul><p>该目录还导出 <code>ApiSwitch</code>，其实现位于 <code>components/global/api-switch.vue</code>，用于应用层的状态切换交互。</p><h3 id="与适配器关系" tabindex="-1">与适配器关系 <a class="header-anchor" href="#与适配器关系" aria-label="Permalink to &quot;与适配器关系&quot;">​</a></h3><ul><li><code>adapter/component/index.ts</code> 通过异步方式接入： <ul><li><code>FileUpload</code></li><li><code>ImageUpload</code></li><li><code>RichTextarea</code>（引用 <code>Tinymce</code>）</li></ul></li><li>这些组件会被映射为 Vben Form 可用组件类型。</li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>若组件只服务 <code>web-antd</code> 业务，优先留在应用层；跨应用复用再考虑抽到 <code>packages</code>。</li><li>新增表单型组件时，要同步更新 <code>adapter/component/index.ts</code> 的 <code>ComponentType</code> 与映射表。</li><li>上传组件相关行为以 <code>components/upload/src/*</code> 与 <code>api/core/upload.ts</code> 的组合逻辑为准。</li></ul>',18)])])}]]);export{c as __pageData,a as default};
